const fs = require('fs');
const path = require('path');

// 读取docx文件（docx本质是zip包，先读取原始字节看看能不能提取文本）
function readDocxSimple(filePath) {
  try {
    const content = fs.readFileSync(filePath);
    // 尝试将二进制内容转为字符串，docx中的文本通常以UTF-8编码的XML形式存在
    const text = content.toString('utf8');
    // 提取可读文本片段
    const cleanText = text.replace(/[\x00-\x08\x0b\x0c\x0e-\x1f]/g, ' ')
                          .replace(/\s+/g, ' ')
                          .substring(0, 500);
    return cleanText;
  } catch(e) {
    return '读取失败: ' + e.message;
  }
}

