const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

// 用python-docx读取docx文件
function readDocxPython(filePath) {
  try {
    const script = `
import sys
sys.path.insert(0, '/opt/homebrew/lib/python3.9/site-packages')
try:
    import docx
    doc = docx.Document("${filePath}")
    for p in doc.paragraphs:
        print(p.text)
except ImportError:
    print("PYTHON_DOCX_NOT_FOUND")
`;
    const result = execSync(`python3 -c "${script.replace(/"/g, '\\"').replace(/\n/g, ' ')}"`, {encoding: 'utf8', timeout: 10000});
    if (result.includes('PYTHON_DOCX_NOT_FOUND')) return null;
    return result;
  } catch(e) {
    return 'ERROR: ' + e.message.substring(0, 200);
  }
}

